import{_ as e,o as s,c as a,ag as n}from"./chunks/framework.DjDv_3Bc.js";const t="/290-datenbanken/assets/select-erklaerung.sdMFVcgd.png",c=JSON.parse('{"title":"Thema 3 - SELECT","description":"","frontmatter":{},"headers":[],"relativePath":"projekt/thema-3-select.md","filePath":"content/projekt/Thema 3 - Select.md","lastUpdated":1777581935000}'),l={name:"projekt/thema-3-select.md"};function h(r,i,p,k,d,o){return s(),a("div",null,[...i[0]||(i[0]=[n(`<h1 id="thema-3-select" tabindex="-1">Thema 3 - SELECT <a class="header-anchor" href="#thema-3-select" aria-label="Permalink to &quot;Thema 3 - SELECT&quot;">​</a></h1><h2 id="auftrag" tabindex="-1">Auftrag <a class="header-anchor" href="#auftrag" aria-label="Permalink to &quot;Auftrag&quot;">​</a></h2><p>Schreibe <strong>5 SELECT Queries</strong> und dokumentiere sie. Die Queries werden später auch vorgetragen.</p><p><strong>Anforderungen:</strong></p><ul><li>1 Query mit einem Filter (<code>WHERE</code>)</li><li>2 Queries mit einer Aggregation (<code>SUM</code>, <code>AVG</code>, ...)</li><li>2 Queries über mehrere Tabellen (<code>JOIN</code>)</li></ul><p>Für jedes Query schreibst du 1–2 Sätze: Was macht der Befehl, und wann wäre er nützlich?</p><hr><h2 id="was-ist-select" tabindex="-1">Was ist SELECT? <a class="header-anchor" href="#was-ist-select" aria-label="Permalink to &quot;Was ist SELECT?&quot;">​</a></h2><p>Mit <code>SELECT</code> lesen wir Daten aus einer Tabelle aus – wir verändern nichts, wir schauen nur.</p><p>Öffne den <a href="https://sqlproject.coffee-journal.com" target="_blank" rel="noreferrer">Dein Projekt</a> und gib im <a href="/290-datenbanken/projekt/sql-tool#query-editor">Query Editor</a> folgendes ein:</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, preis</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> produkte;</span></span></code></pre></div><p>Dieser Befehl zeigt die Spalten <code>name</code> und <code>preis</code> aus der Tabelle <code>produkte</code>. Passe ihn auf deine eigene Tabelle an und klicke auf <strong>Run Query</strong>. Du solltest eine Tabelle mit Daten sehen.</p><blockquote><p>💡 Du weisst nicht mehr, wie deine Tabellen heissen? <a href="/290-datenbanken/projekt/sql-tool#meine-tabellen">Hier nachschauen.</a></p></blockquote><p><img src="`+t+`" alt="Erklärung SELECT"></p><hr><h2 id="query-1-–-where-filter" tabindex="-1">Query 1 – WHERE (Filter) <a class="header-anchor" href="#query-1-–-where-filter" aria-label="Permalink to &quot;Query 1 – WHERE (Filter)&quot;">​</a></h2><p>Mit <code>WHERE</code> zeigen wir nur die Zeilen, die eine bestimmte Bedingung erfüllen.</p><p><strong>Beispiel:</strong> Alle Produkte, die weniger als 5 Franken kosten:</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, preis</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> produkte</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> preis </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>⚡️ Überlege dir einen sinnvollen Filter für deine Tabelle und schreibe dein eigenes Query.</p><p>✅ Dokumentiere: Was filtert dein Query, und wann wäre das nützlich?</p><hr><h2 id="query-2-3-–-join-zwei-tabellen-verbinden" tabindex="-1">Query 2 &amp; 3 – JOIN (zwei Tabellen verbinden) <a class="header-anchor" href="#query-2-3-–-join-zwei-tabellen-verbinden" aria-label="Permalink to &quot;Query 2 &amp; 3 – JOIN (zwei Tabellen verbinden)&quot;">​</a></h2><p>Mit <code>JOIN</code> kombinieren wir Daten aus zwei Tabellen. Das macht Sinn, wenn Daten zusammengehören, aber in verschiedenen Tabellen stehen – zum Beispiel Produkte und ihre Bewertungen.</p><p><strong>Beispiel:</strong></p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> produkte</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">name</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> AS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> produkt, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">produkte</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">preis</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> AS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> preis, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">bewertungen</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">kommentar</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> AS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> kommentar</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> produkte</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">JOIN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> bewertungen </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ON</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> produkte</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">id</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> bewertungen</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">produkt_id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>Was passiert hier?</p><ul><li><code>FROM produkte</code> – wir starten mit der Tabelle <code>produkte</code></li><li><code>JOIN bewertungen</code> – wir fügen die Tabelle <code>bewertungen</code> hinzu</li><li><code>ON produkte.id = bewertungen.produkt_id</code> – wir sagen, wie die zwei Tabellen zusammenhängen: die <code>id</code> aus <code>produkte</code> entspricht der <code>produkt_id</code> in <code>bewertungen</code></li><li><code>AS</code> benennt die Spalten im Ergebnis um</li></ul><p>⚡️ Wähle zwei Tabellen aus deinem Projekt, die miteinander verbunden sind. Schreibe zwei verschiedene JOIN Queries.</p><p>✅ Dokumentiere beide Queries: Welche Tabellen verbindest du, und was zeigt das Ergebnis?</p><h3 id="n-m-beziehung-optional" tabindex="-1">N:M Beziehung (optional) <a class="header-anchor" href="#n-m-beziehung-optional" aria-label="Permalink to &quot;N:M Beziehung (optional)&quot;">​</a></h3><p>Wenn zwei Tabellen über eine <strong>Zwischentabelle</strong> verbunden sind (n:m), brauchst du zwei <code>JOIN</code>s:</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> produkte</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">name</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> AS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> produkt, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">kategorien</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">name</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> AS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> kategorie</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> produkte</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">JOIN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> produkt_kategorien </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ON</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> produkte</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">id</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> produkt_kategorien</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">produkt_id</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">JOIN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> kategorien </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ON</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> kategorien</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">id</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> produkt_kategorien</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">kategorie_id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>Hier verbinden wir <code>produkte</code> und <code>kategorien</code> über die Zwischentabelle <code>produkt_kategorien</code>.</p><hr><h2 id="query-4-5-–-aggregation-werte-berechnen" tabindex="-1">Query 4 &amp; 5 – Aggregation (Werte berechnen) <a class="header-anchor" href="#query-4-5-–-aggregation-werte-berechnen" aria-label="Permalink to &quot;Query 4 &amp; 5 – Aggregation (Werte berechnen)&quot;">​</a></h2><p>Mit Aggregationsfunktionen berechnen wir Werte aus mehreren Zeilen – zum Beispiel eine Summe oder einen Durchschnitt. Das Ergebnis ist immer eine einzelne Zahl.</p><p>Die wichtigsten Funktionen:</p><table tabindex="0"><thead><tr><th>Funktion</th><th>Was sie macht</th></tr></thead><tbody><tr><td><code>SUM</code></td><td>Addiert alle Werte einer Spalte</td></tr><tr><td><code>AVG</code></td><td>Berechnet den Durchschnitt</td></tr><tr><td><code>COUNT</code></td><td>Zählt die Anzahl Zeilen</td></tr><tr><td><code>MAX</code> / <code>MIN</code></td><td>Gibt den grössten / kleinsten Wert zurück</td></tr></tbody></table><p><strong>Beispiele:</strong></p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- Wie viel kosten alle Produkte zusammen?</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> SUM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(preis) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> gesamtpreis</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> produkte;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- Was ist der Durchschnittspreis?</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> AVG</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(preis) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> durchschnittspreis</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> produkte;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- Wie viele Produkte gibt es?</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> COUNT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> anzahl_produkte</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> produkte;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- Was ist das teuerste und günstigste Produkt?</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> MAX</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(preis) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> teuerster, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">MIN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(preis) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> guenstigster</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> produkte;</span></span></code></pre></div><p>⚡️ Schreibe zwei eigene Aggregations-Queries für deine Tabellen. Verwende dabei mindestens zwei verschiedene Funktionen.</p><h3 id="group-by-–-gruppiert-berechnen" tabindex="-1">GROUP BY – Gruppiert berechnen <a class="header-anchor" href="#group-by-–-gruppiert-berechnen" aria-label="Permalink to &quot;GROUP BY – Gruppiert berechnen&quot;">​</a></h3><p>Manchmal wollen wir nicht einen Wert für die <strong>gesamte</strong> Tabelle, sondern einen Wert <strong>pro Gruppe</strong>. Dafür gibt es <code>GROUP BY</code>.</p><p><strong>Beispiel:</strong> Den Durchschnittspreis pro Kategorie berechnen:</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> kategorie, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">AVG</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(preis) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> durchschnittspreis</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> produkte</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">GROUP BY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> kategorie;</span></span></code></pre></div><p>Was passiert hier?</p><ul><li><code>GROUP BY kategorie</code> – die Tabelle wird nach <code>kategorie</code> gruppiert</li><li><code>AVG(preis)</code> – der Durchschnitt wird <strong>pro Gruppe</strong> berechnet, nicht für alle Produkte zusammen</li></ul><p>Stell dir vor, du hast Produkte in den Kategorien „Getränke&quot; und „Snacks&quot;. Ohne <code>GROUP BY</code> bekommst du <strong>einen</strong> Durchschnitt für alles. Mit <code>GROUP BY kategorie</code> bekommst du <strong>einen Durchschnitt pro Kategorie</strong>.</p><p>⚡️ Überlege, welche Spalte in deiner Tabelle sich zum Gruppieren eignet, und schreibe ein Query mit <code>GROUP BY</code>.</p><p>✅ Dokumentiere beide Queries: Was berechnen sie, und in welcher Situation wären diese Informationen nützlich?</p>`,51)])])}const E=e(l,[["render",h]]);export{c as __pageData,E as default};
